// Handle Enter Key
function handleKeyDown(e) {
    if (e.key === 'Enter' && !e.shiftKey) {
        e.preventDefault();
        sendMessage();
    }
}

// Auto Resize Textarea
function autoResize(textarea) {
    textarea.style.height = 'auto';
    textarea.style.height = Math.min(textarea.scrollHeight, 120) + 'px';
}

// Get Current Time
function getCurrentTime() {
    return new Date().toLocaleTimeString('id-ID', { 
        hour: '2-digit', 
        minute: '2-digit' 
    });
}

// Estimate tokens (rough: ~4 chars per token)
function estimateTokens(text) {
    return Math.ceil(text.length / 4);
}

// Format number with K/M suffix
function formatNumber(num) {
    if (num >= 1000000) return (num / 1000000).toFixed(1) + 'M';
    if (num >= 1000) return (num / 1000).toFixed(1) + 'K';
    return num.toString();
}

// ========== TOKEN DASHBOARD FUNCTIONS ==========

// Toggle token panel
function toggleTokenPanel() {
    const panel = document.getElementById('tokenPanel');
    const arrow = document.getElementById('tokenArrow');
    panel.classList.toggle('open');
    arrow.classList.toggle('open');
}

// Update ring chart
function updateRing(id, percentage) {
    const ring = document.getElementById(id);
    const circumference = 251.2;
    const offset = circumference - (Math.min(percentage, 100) / 100) * circumference;
    ring.style.strokeDashoffset = offset;
}

// Animate number change
function animateNumber(elementId, newValue) {
    const el = document.getElementById(elementId);
    if (el) {
        el.textContent = newValue;
        el.classList.remove('number-pop');
        void el.offsetWidth; // Trigger reflow
        el.classList.add('number-pop');
    }
}

// Update all token displays
function updateTokenDisplay() {
    const { totalInput, totalOutput, totalTokens, messageCount, userTokens, botTokens, maxTokens } = tokenStats;

    // Mini header display
    animateNumber('tokenTotalMini', formatNumber(totalTokens));

    // Ring numbers
    animateNumber('ringInputNum', formatNumber(totalInput));
    animateNumber('ringOutputNum', formatNumber(totalOutput));
    animateNumber('ringTotalNum', formatNumber(totalTokens));

    // Ring charts (percentage of maxTokens)
    const inputPct = (totalInput / maxTokens) * 100;
    const outputPct = (totalOutput / maxTokens) * 100;
    const totalPct = (totalTokens / maxTokens) * 100;

    updateRing('ringInput', inputPct);
    updateRing('ringOutput', outputPct);
    updateRing('ringTotal', totalPct);

    // Progress bar
    const usedPct = Math.min((totalTokens / maxTokens) * 100, 100);
    document.getElementById('tokenProgressBar').style.width = usedPct + '%';
    document.getElementById('progressUsed').textContent = formatNumber(totalTokens) + ' tokens';
    document.getElementById('progressLimit').textContent = '/' + formatNumber(maxTokens);
    document.getElementById('sessionStats').textContent = messageCount + ' pesan • ' + formatNumber(totalTokens) + ' token';

    // Stats grid
    animateNumber('statMessages', messageCount);
    animateNumber('statUserTokens', formatNumber(userTokens));
    animateNumber('statBotTokens', formatNumber(botTokens));

    const avgPerMsg = messageCount > 0 ? formatNumber(Math.round(totalTokens / messageCount)) : '0';
    document.getElementById('statAvgPerMsg').textContent = avgPerMsg;
}

// Reset token stats
